import numpy as np

def probability_of_heads(coin_probs, n):
    total_prob = 0
    for combo in itertools.combinations(coin_probs, n):
        prob = np.prod(combo) * np.prod([1 - p for p in coin_probs if p not in combo])
        total_prob += prob
    return total_prob

def best_set_brute_force(coin_probs):
    n = len(coin_probs) // 2
    best_prob = 0
    best_set = None
    for combo in itertools.combinations(coin_probs, n):
        prob = probability_of_heads(combo, n)
        if prob > best_prob:
            best_prob = prob
            best_set = combo
    return best_set, best_prob

def best_set_dynamic(coin_probs):
    n = len(coin_probs) // 2
    dp = np.zeros((n + 1, len(coin_probs) + 1))
    for i in range(1, len(coin_probs) + 1):
        for j in range(min(i, n) + 1):
            dp[j][i] = dp[j][i - 1]
            if j > 0:
                dp[j][i] = max(dp[j][i], dp[j - 1][i - 1] + np.log(coin_probs[i - 1]))

    best_prob = np.exp(dp[n][len(coin_probs)])
    best_set = []
    j = n
    for i in range(len(coin_probs), 0, -1):
        if dp[j][i] != dp[j][i - 1]:
            best_set.append(coin_probs[i - 1])
            j -= 1
    return best_set, best_prob

