    brute_force_set, brute_force_prob = best_set_brute_force(coin_probs)
    dynamic_set, dynamic_prob = best_set_dynamic(coin_probs)
    return {
        "Brute Force": (brute_force_set, brute_force_prob),
        "Dynamic Programming": (dynamic_set, dynamic_prob)
    }

